// ── BUILTIN PATCHES — auto-run on every load, no manual apply needed ────────
// These were originally separate patch files, now baked into the app.
const BUILTIN_PATCHES = {
  "task_import_export": "// PATCH_ID: shic-patch-task-import-export-v1.0.0\n// PATCH_VERSION: 1.0.0\n// PATCH_TYPE: persistent\n// DESCRIPTION: Adds Import and Export (Excel/CSV) to Task Management. Upload tasks from Excel/CSV template, download all tasks as Excel. Includes template download.\n\n(function(){\n'use strict';\n\n// \u2500\u2500 REQUIRED COLUMNS for import \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar TASK_COLS = [\n  'WBS','Task Name','Project ID','Assignee','Department',\n  'Start Date','End Date','Planned Hrs','Actual Hrs',\n  'Status','Priority','Progress %','Milestone'\n];\n\n// \u2500\u2500 1. EXPORT TASKS TO EXCEL \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.exportTasksExcel = function(projectFilter){\n  var tasks = (AppState.data.tasks||[]);\n  if(projectFilter && projectFilter!=='all'){\n    tasks = tasks.filter(function(t){return t.projectId===projectFilter;});\n  }\n  if(!tasks.length){showToast('No tasks to export','warning');return;}\n\n  // Build CSV content (opens in Excel)\n  var rows = [TASK_COLS.join(',')];\n  tasks.forEach(function(t){\n    rows.push([\n      _csvCell(t.wbs||t.id),\n      _csvCell(t.name),\n      _csvCell(t.projectId),\n      _csvCell(t.assignee),\n      _csvCell(t.dept),\n      _csvCell(t.startDate),\n      _csvCell(t.endDate),\n      t.plannedHrs||0,\n      t.actualHrs||0,\n      _csvCell(t.status||'todo'),\n      _csvCell(t.priority||'normal'),\n      t.progress||0,\n      t.milestone?'Yes':'No'\n    ].join(','));\n  });\n\n  var blob = new Blob([rows.join('\\r\\n')], {type:'text/csv;charset=utf-8;'});\n  var url = URL.createObjectURL(blob);\n  var a = document.createElement('a');\n  a.href = url;\n  a.download = 'SHIC_Tasks_'+(projectFilter&&projectFilter!=='all'?projectFilter:'All')+'_'+new Date().toISOString().split('T')[0]+'.csv';\n  a.click();\n  URL.revokeObjectURL(url);\n  showToast('Exported '+tasks.length+' tasks','success');\n};\n\n// \u2500\u2500 2. DOWNLOAD BLANK TEMPLATE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.downloadTaskTemplate = function(){\n  var header = TASK_COLS.join(',');\n  // Include sample row\n  var projects = (AppState.data.projects||[]);\n  var projId = projects.length?projects[0].id:'PRJ-001';\n  var sample = [\n    '1.1.1',\n    'Sample Task Name',\n    projId,\n    'Juan dela Cruz',\n    'Engineering',\n    new Date().toISOString().split('T')[0],\n    new Date(Date.now()+7*24*60*60*1000).toISOString().split('T')[0],\n    '40','0','todo','normal','0','No'\n  ].map(_csvCell).join(',');\n\n  var instructions = [\n    '# SHIC Task Import Template',\n    '# Instructions:',\n    '# - Do not change column headers (Row 2)',\n    '# - Status values: todo | inprogress | done | blocked',\n    '# - Priority values: critical | high | medium | low | normal',\n    '# - Progress: 0-100 (number only)',\n    '# - Milestone: Yes or No',\n    '# - Dates: YYYY-MM-DD format',\n    '# - Delete these instruction rows before importing',\n    '#',\n    header,\n    sample\n  ].join('\\r\\n');\n\n  var blob = new Blob([instructions],{type:'text/csv;charset=utf-8;'});\n  var url = URL.createObjectURL(blob);\n  var a = document.createElement('a');\n  a.href = url;\n  a.download = 'SHIC_Task_Import_Template.csv';\n  a.click();\n  URL.revokeObjectURL(url);\n  showToast('Template downloaded \u2014 fill it in and import','info',3000);\n};\n\n// \u2500\u2500 3. SHOW IMPORT MODAL \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.showTaskImport = function(){\n  document.getElementById('genericModalTitle').textContent = 'Import Tasks from CSV / Excel';\n  document.getElementById('genericModalBody').innerHTML = `\n  <div style=\"margin-bottom:14px;padding:12px;background:rgba(56,139,253,.08);border:1px solid rgba(56,139,253,.2);border-radius:8px\">\n    <div style=\"font-size:12px;font-weight:600;color:var(--accent-blue);margin-bottom:6px\">\n      <i class=\"fas fa-info-circle\" style=\"margin-right:6px\"></i>Import Instructions\n    </div>\n    <div style=\"font-size:11px;color:var(--text-secondary);line-height:1.6\">\n      \u2022 Download the template, fill it in Excel/Sheets, save as <strong>.csv</strong><br>\n      \u2022 Required columns: <strong>Task Name</strong> and <strong>Project ID</strong><br>\n      \u2022 Status: <code>todo</code> | <code>inprogress</code> | <code>done</code> | <code>blocked</code><br>\n      \u2022 Priority: <code>critical</code> | <code>high</code> | <code>medium</code> | <code>low</code><br>\n      \u2022 Lines starting with <code>#</code> are skipped (comments)<br>\n      \u2022 Existing tasks with matching WBS codes will be <strong>updated</strong><br>\n      \u2022 New tasks will be <strong>added</strong> \u2014 nothing is deleted\n    </div>\n  </div>\n\n  <div style=\"display:flex;gap:8px;margin-bottom:14px\">\n    <button class=\"btn btn-secondary\" onclick=\"window.downloadTaskTemplate()\" style=\"flex:1\">\n      <i class=\"fas fa-download\" style=\"margin-right:6px\"></i>Download Template\n    </button>\n    <button class=\"btn btn-secondary\" onclick=\"window.exportTasksExcel(window.taskProjectFilter||'all')\" style=\"flex:1\">\n      <i class=\"fas fa-file-export\" style=\"margin-right:6px\"></i>Export Current Tasks\n    </button>\n  </div>\n\n  <div style=\"margin-bottom:10px\">\n    <label class=\"form-label\">Import Mode</label>\n    <div style=\"display:flex;gap:8px;margin-top:5px\">\n      <label style=\"display:flex;align-items:center;gap:6px;cursor:pointer;font-size:12px\">\n        <input type=\"radio\" name=\"importMode\" value=\"add\" checked> Add new + update existing (safe)\n      </label>\n      <label style=\"display:flex;align-items:center;gap:6px;cursor:pointer;font-size:12px\">\n        <input type=\"radio\" name=\"importMode\" value=\"replace\"> Replace all tasks\n      </label>\n    </div>\n  </div>\n\n  <div class=\"form-group\">\n    <label class=\"form-label\">Select CSV File *</label>\n    <input type=\"file\" id=\"taskImportFile\" accept=\".csv,.txt\"\n      class=\"form-input\" style=\"padding:6px\"\n      onchange=\"window.previewTaskImport(this)\">\n  </div>\n\n  <div id=\"taskImportPreview\" style=\"margin-top:10px\"></div>`;\n\n  document.getElementById('genericModalFooter').innerHTML = `\n    <button class=\"btn btn-secondary\" onclick=\"closeModal('genericModal')\">Cancel</button>\n    <button class=\"btn btn-primary\" id=\"taskImportBtn\" disabled style=\"opacity:.4;cursor:not-allowed\"\n      onclick=\"window.executeTaskImport()\">\n      <i class=\"fas fa-file-import\"></i> Import Tasks\n    </button>`;\n\n  if(typeof openModal==='function')openModal('genericModal');\n};\n\n// \u2500\u2500 4. PREVIEW IMPORT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow._taskImportData = null;\nwindow.previewTaskImport = function(input){\n  var file = input.files[0];\n  if(!file)return;\n  var reader = new FileReader();\n  reader.onload = function(e){\n    var text = e.target.result;\n    var result = _parseTaskCSV(text);\n    window._taskImportData = result.rows;\n\n    var prev = document.getElementById('taskImportPreview');\n    if(!prev)return;\n\n    if(result.errors.length&&!result.rows.length){\n      prev.innerHTML='<div style=\"padding:10px;background:rgba(248,81,73,.1);border-radius:6px;color:var(--accent-red);font-size:11px\">'+\n        '<strong>Parse error:</strong><br>'+result.errors.join('<br>')+'</div>';\n      return;\n    }\n\n    var projects = (AppState.data.projects||[]).map(function(p){return p.id;});\n    var warnings = [];\n    result.rows.forEach(function(r){\n      if(!projects.includes(r.projectId)) warnings.push('Project \"'+r.projectId+'\" not found \u2014 row: '+r.name);\n    });\n\n    prev.innerHTML = `\n    <div style=\"padding:10px;background:rgba(63,185,80,.08);border:1px solid rgba(63,185,80,.2);border-radius:6px;margin-bottom:8px\">\n      <div style=\"font-size:12px;font-weight:600;color:var(--accent-green)\">\n        <i class=\"fas fa-check-circle\" style=\"margin-right:6px\"></i>\n        ${result.rows.length} task(s) ready to import\n      </div>\n      ${warnings.length?'<div style=\"font-size:10px;color:var(--accent-amber);margin-top:5px\">\u26a0 '+warnings.length+' warning(s): '+warnings.join('; ')+'</div>':''}\n    </div>\n    <div style=\"max-height:180px;overflow-y:auto;border:1px solid var(--border);border-radius:6px\">\n      <table style=\"width:100%;border-collapse:collapse;font-size:10px\">\n        <thead><tr style=\"background:var(--bg-hover)\">\n          <th style=\"padding:5px 8px;text-align:left\">Task Name</th>\n          <th style=\"padding:5px 8px;text-align:left\">Project</th>\n          <th style=\"padding:5px 8px;text-align:left\">Assignee</th>\n          <th style=\"padding:5px 8px;text-align:left\">Status</th>\n          <th style=\"padding:5px 8px;text-align:left\">End Date</th>\n        </tr></thead>\n        <tbody>\n          ${result.rows.slice(0,50).map(function(r,i){\n            return'<tr style=\"border-top:1px solid var(--border);background:'+(i%2===0?'transparent':'var(--bg-hover)')+'\">'+\n              '<td style=\"padding:4px 8px;font-weight:500\">'+r.name+'</td>'+\n              '<td style=\"padding:4px 8px\"><span class=\"badge badge-blue\">'+r.projectId+'</span></td>'+\n              '<td style=\"padding:4px 8px\">'+r.assignee+'</td>'+\n              '<td style=\"padding:4px 8px\">'+r.status+'</td>'+\n              '<td style=\"padding:4px 8px;font-family:var(--font-mono)\">'+r.endDate+'</td>'+\n            '</tr>';\n          }).join('')}\n          ${result.rows.length>50?'<tr><td colspan=\"5\" style=\"padding:5px 8px;color:var(--text-muted)\">...and '+(result.rows.length-50)+' more</td></tr>':''}\n        </tbody>\n      </table>\n    </div>`;\n\n    var btn = document.getElementById('taskImportBtn');\n    if(btn&&result.rows.length){\n      btn.disabled=false;\n      btn.style.opacity='1';\n      btn.style.cursor='pointer';\n    }\n  };\n  reader.readAsText(file);\n};\n\n// \u2500\u2500 5. EXECUTE IMPORT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.executeTaskImport = function(){\n  var rows = window._taskImportData;\n  if(!rows||!rows.length){showToast('No data to import','error');return;}\n\n  var modeEl = document.querySelector('input[name=\"importMode\"]:checked');\n  var mode = modeEl?modeEl.value:'add';\n\n  AppState.ensureData();\n  var existing = AppState.data.tasks||[];\n  var added=0, updated=0;\n\n  if(mode==='replace'){\n    AppState.data.tasks = rows;\n    added = rows.length;\n  }else{\n    rows.forEach(function(newTask){\n      // Match by WBS if set, otherwise by name+projectId\n      var idx = -1;\n      if(newTask.wbs){\n        idx = existing.findIndex(function(t){return t.wbs===newTask.wbs&&t.projectId===newTask.projectId;});\n      }\n      if(idx<0){\n        idx = existing.findIndex(function(t){\n          return t.name.trim().toLowerCase()===newTask.name.trim().toLowerCase()&&t.projectId===newTask.projectId;\n        });\n      }\n      if(idx>=0){\n        existing[idx] = Object.assign({},existing[idx],newTask);\n        updated++;\n      }else{\n        existing.push(newTask);\n        added++;\n      }\n    });\n    AppState.data.tasks = existing;\n  }\n\n  AppState.save();\n  closeModal('genericModal');\n  if(typeof renderTaskView==='function')renderTaskView();\n  if(typeof renderTasks==='function')renderTasks();\n  showToast('Import complete: '+added+' added, '+updated+' updated','success',4000);\n  window._taskImportData=null;\n};\n\n// \u2500\u2500 6. CSV PARSER \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction _parseTaskCSV(text){\n  var lines = text.replace(/\\r\\n/g,'\\n').replace(/\\r/g,'\\n').split('\\n');\n  var errors = [];\n  var headerLine = -1;\n  var headers = [];\n\n  // Find header row (skip # comment lines)\n  for(var i=0;i<lines.length;i++){\n    var line = lines[i].trim();\n    if(!line||line.startsWith('#'))continue;\n    var cols = _csvParseLine(line);\n    // Check if this looks like a header row\n    if(cols.some(function(c){return c.trim().toLowerCase()==='task name';})){\n      headers = cols.map(function(c){return c.trim().toLowerCase();});\n      headerLine = i;\n      break;\n    }\n  }\n\n  if(headerLine<0){\n    errors.push('Header row not found. Make sure \"Task Name\" column exists.');\n    return{rows:[],errors:errors};\n  }\n\n  var rows = [];\n  var validStatuses = ['todo','inprogress','in-progress','done','completed','blocked','on-hold'];\n  var validPriorities = ['critical','high','medium','normal','low'];\n\n  for(var j=headerLine+1;j<lines.length;j++){\n    var line2 = lines[j].trim();\n    if(!line2||line2.startsWith('#'))continue;\n    var vals = _csvParseLine(line2);\n    if(!vals.some(function(v){return v.trim();}))continue; // empty row\n\n    var row = {};\n    headers.forEach(function(h,idx){\n      row[h] = (vals[idx]||'').trim();\n    });\n\n    var name = row['task name']||row['name']||'';\n    if(!name)continue;\n\n    var status = (row['status']||'todo').toLowerCase().replace(/[^a-z-]/g,'');\n    if(!validStatuses.includes(status))status='todo';\n    if(status==='in-progress')status='inprogress';\n    if(status==='completed')status='done';\n\n    var priority = (row['priority']||'normal').toLowerCase();\n    if(!validPriorities.includes(priority))priority='normal';\n\n    var progress = parseInt(row['progress %']||row['progress']||0)||0;\n    progress = Math.max(0,Math.min(100,progress));\n\n    rows.push({\n      id: 'TSK-'+(Date.now()%100000+j).toString().padStart(5,'0')+'-'+Math.random().toString(36).slice(2,5),\n      wbs: row['wbs']||row['wbs code']||'',\n      name: name,\n      projectId: row['project id']||row['project']||'',\n      assignee: row['assignee']||row['assigned to']||'',\n      dept: row['department']||row['dept']||'',\n      startDate: _normalizeDate(row['start date']||row['start']||''),\n      endDate: _normalizeDate(row['end date']||row['end']||row['due date']||''),\n      plannedHrs: parseFloat(row['planned hrs']||row['planned hours']||0)||0,\n      actualHrs: parseFloat(row['actual hrs']||row['actual hours']||0)||0,\n      status: status,\n      priority: priority,\n      progress: progress,\n      milestone: (row['milestone']||'no').toLowerCase()==='yes',\n    });\n  }\n\n  if(!rows.length)errors.push('No valid data rows found after header.');\n  return{rows:rows,errors:errors};\n}\n\nfunction _csvParseLine(line){\n  var result=[],current='',inQuotes=false;\n  for(var i=0;i<line.length;i++){\n    var c=line[i];\n    if(c==='\"'){if(inQuotes&&line[i+1]==='\"'){current+='\"';i++;}else inQuotes=!inQuotes;}\n    else if(c===','&&!inQuotes){result.push(current);current='';}\n    else current+=c;\n  }\n  result.push(current);\n  return result;\n}\n\nfunction _csvCell(val){\n  var s=String(val===null||val===undefined?'':val);\n  if(s.includes(',')||s.includes('\"')||s.includes('\\n'))return'\"'+s.replace(/\"/g,'\"\"')+'\"';\n  return s;\n}\n\nfunction _normalizeDate(d){\n  if(!d)return'';\n  // Handle MM/DD/YYYY, DD/MM/YYYY, YYYY-MM-DD\n  var iso=/^\\d{4}-\\d{2}-\\d{2}$/.test(d);\n  if(iso)return d;\n  var parts=d.split(/[\\/\\-\\.]/);\n  if(parts.length===3){\n    if(parts[2].length===4)return parts[2]+'-'+parts[1].padStart(2,'0')+'-'+parts[0].padStart(2,'0');\n    if(parts[0].length===4)return parts[0]+'-'+parts[1].padStart(2,'0')+'-'+parts[2].padStart(2,'0');\n  }\n  return d;\n}\n\n// \u2500\u2500 7. PATCH renderTasks to add Import/Export buttons \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar _origRenderTasks = window.renderTasks;\nwindow.renderTasks = function(){\n  _origRenderTasks();\n  // Inject Import/Export buttons into section header\n  setTimeout(function(){\n    var el = document.getElementById('tasks');\n    if(!el)return;\n    var header = el.querySelector('.section-header');\n    if(!header||header.querySelector('[data-task-io-btns]'))return;\n    var btnArea = header.querySelector('div:last-child');\n    if(!btnArea)return;\n\n    var ioDiv = document.createElement('div');\n    ioDiv.setAttribute('data-task-io-btns','1');\n    ioDiv.style.cssText='display:flex;gap:6px;align-items:center';\n    ioDiv.innerHTML=\n      '<button class=\"btn btn-secondary btn-sm\" onclick=\"window.showTaskImport()\" title=\"Import tasks from CSV\">'+\n        '<i class=\"fas fa-file-import\" style=\"margin-right:5px\"></i>Import</button>'+\n      '<button class=\"btn btn-secondary btn-sm\" onclick=\"window.exportTasksExcel(window.taskProjectFilter||\\'all\\')\" title=\"Export tasks to CSV\">'+\n        '<i class=\"fas fa-file-export\" style=\"margin-right:5px\"></i>Export</button>';\n\n    btnArea.insertBefore(ioDiv, btnArea.firstChild);\n  },80);\n};\n\n// Re-render if on tasks page\nif(typeof AppState!=='undefined'&&AppState.currentPage==='tasks'){\n  if(typeof renderTasks==='function')renderTasks();\n}\n\nconsole.log('[SHIC Patch] Task Import/Export loaded');\nshowToast('Task Import/Export ready \u2014 Import & Export buttons added to Task Management','success',3000);\n\n})();\n",
  "trade_cost_masterlist": "// PATCH_ID: shic-patch-trade-cost-masterlist-v1.0.0\n// PATCH_VERSION: 1.0.1\n// PATCH_TYPE: persistent\n// DESCRIPTION: Upgrades Trade/Discipline Masterlist with cost rates (Daily, Monthly, OT). Import/Export CSV. v1.0.1 fixes CSV parser \u2014 handles \u20b1 symbol, slash in headers, extra spaces.\n\n(function(){\n'use strict';\n\n// \u2500\u2500 CSV HELPERS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction csvCell(v){\n  var s=String(v===null||v===undefined?'':v);\n  if(s.includes(',')||s.includes('\"')||s.includes('\\n'))return'\"'+s.replace(/\"/g,'\"\"')+'\"';\n  return s;\n}\nfunction csvParseLine(line){\n  var res=[],cur='',inQ=false;\n  for(var i=0;i<line.length;i++){\n    var c=line[i];\n    if(c==='\"'){if(inQ&&line[i+1]==='\"'){cur+='\"';i++;}else inQ=!inQ;}\n    else if(c===','&&!inQ){res.push(cur);cur='';}\n    else cur+=c;\n  }\n  res.push(cur);\n  return res.map(function(s){return s.trim();});\n}\n// Normalize a header string: lowercase, strip special chars, collapse spaces\nfunction normalizeHeader(h){\n  return h.toLowerCase()\n    .replace(/[\u20b1\\?\\(\\)\\/\\\\]/g,' ')   // replace \u20b1 ? ( ) / \\ with space\n    .replace(/[^\\w\\s]/g,'')           // strip remaining special chars\n    .replace(/\\s+/g,' ')              // collapse multiple spaces\n    .trim();\n}\n\n// \u2500\u2500 TRADE OBJECT helpers \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction toTradeObj(t){\n  if(typeof t==='string')return{name:t,dailyRate:0,monthlyRate:0,overtimeRate:0,currency:'PHP',notes:''};\n  return Object.assign({dailyRate:0,monthlyRate:0,overtimeRate:0,currency:'PHP',notes:''},t);\n}\nfunction tradeName(t){return typeof t==='string'?t:(t&&t.name?t.name:'');}\nwindow.getTradeName=tradeName;\n\n// \u2500\u2500 AUTO-MIGRATE string trades \u2192 objects \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n(function(){\n  AppState.ensureData();\n  if(!AppState.data.trades)AppState.data.trades=[];\n  if(AppState.data.trades.some(function(t){return typeof t==='string';})){\n    AppState.data.trades=AppState.data.trades.map(toTradeObj);\n    AppState.save();\n    console.log('[Trade Patch] Migrated trades to object format');\n  }\n})();\n\n// \u2500\u2500 EXPORT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.exportTradeMasterlist=function(){\n  var trades=(AppState.data.trades||[]).map(toTradeObj).sort(function(a,b){return a.name.localeCompare(b.name);});\n  if(!trades.length){showToast('No trades to export','warning');return;}\n  var rows=[\n    '# SHIC Trade/Discipline Masterlist Export \u2014 '+new Date().toLocaleDateString(),\n    '# Reimport: keep headers, update rates, save as .csv',\n    '#',\n    'Trade / Discipline,Daily Rate (PHP),Monthly Rate (PHP),OT Rate (PHP/hr),Currency,Notes'\n  ];\n  trades.forEach(function(t){\n    rows.push([csvCell(t.name),t.dailyRate||0,t.monthlyRate||0,t.overtimeRate||0,t.currency||'PHP',csvCell(t.notes||'')].join(','));\n  });\n  var blob=new Blob([rows.join('\\r\\n')],{type:'text/csv;charset=utf-8;'});\n  var url=URL.createObjectURL(blob);\n  var a=document.createElement('a');a.href=url;\n  a.download='SHIC_Trade_Masterlist_'+new Date().toISOString().split('T')[0]+'.csv';\n  a.click();URL.revokeObjectURL(url);\n  showToast('Exported '+trades.length+' trades','success');\n};\n\n// \u2500\u2500 DOWNLOAD TEMPLATE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.downloadTradeMasterlistTemplate=function(){\n  var rows=[\n    '# SHIC Trade/Discipline Masterlist Template',\n    '# Instructions:',\n    '# - Required column: Trade / Discipline',\n    '# - Daily Rate: cost per 8-hour day (PHP)',\n    '# - Monthly Rate: auto-calculated (Daily x 22) if 0',\n    '# - OT Rate: auto-calculated (Daily / 8 x 1.25) if 0',\n    '# - Delete these # comment rows before importing (or leave them \u2014 they are skipped)',\n    '#',\n    'Trade / Discipline,Daily Rate (PHP),Monthly Rate (PHP),OT Rate (PHP/hr),Currency,Notes',\n    'Structural Fitter,1200,26400,187.5,PHP,',\n    'Pipe Welder,1500,33000,234.375,PHP,',\n    'TIG Welder,1800,39600,281.25,PHP,Certified TIG',\n    'SMAW Welder,1400,30800,218.75,PHP,',\n    'Rigger/Signalman,1100,24200,171.875,PHP,',\n    'Scaffolder,1000,22000,156.25,PHP,',\n    'Electrician,1300,28600,203.125,PHP,',\n    'Instrumentation Tech,1600,35200,250,PHP,',\n    'Mechanical Fitter,1250,27500,195.3125,PHP,',\n    'Safety Officer,1400,30800,218.75,PHP,',\n    'QC Inspector,1500,33000,234.375,PHP,',\n    'Helper/Laborer,800,17600,125,PHP,',\n  ].join('\\r\\n');\n  var blob=new Blob([rows],{type:'text/csv;charset=utf-8;'});\n  var url=URL.createObjectURL(blob);\n  var a=document.createElement('a');a.href=url;a.download='SHIC_Trade_Masterlist_Template.csv';\n  a.click();URL.revokeObjectURL(url);\n  showToast('Template downloaded','info',2500);\n};\n\n// \u2500\u2500 CSV PARSER (v1.0.1 \u2014 fixed header normalization) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction _parseTradeMasterlistCSV(text){\n  var lines=text.replace(/\\r\\n/g,'\\n').replace(/\\r/g,'\\n').split('\\n');\n  var errors=[],headers=[],headerIdx={},headerLine=-1;\n\n  // Find header row\n  for(var i=0;i<lines.length;i++){\n    var l=lines[i].trim();\n    if(!l||l.startsWith('#'))continue;\n    var cols=csvParseLine(l);\n    var normalized=cols.map(normalizeHeader);\n    // Check if this looks like a header row (contains 'trade' or 'discipline')\n    if(normalized.some(function(h){return h.indexOf('trade')>=0||h.indexOf('discipline')>=0;})){\n      headers=normalized;\n      // Build index map\n      normalized.forEach(function(h,idx){headerIdx[h]=idx;});\n      headerLine=i;\n      break;\n    }\n  }\n\n  if(headerLine<0){\n    errors.push('Header row not found. Make sure \"Trade / Discipline\" column exists.');\n    return{rows:[],errors:errors};\n  }\n\n  console.log('[Trade Import] Headers found:',headers);\n\n  // Helper: get value from row by multiple possible normalized header names\n  function getVal(vals,candidates){\n    for(var k=0;k<candidates.length;k++){\n      var norm=normalizeHeader(candidates[k]);\n      if(norm in headerIdx&&vals[headerIdx[norm]]!==undefined)return vals[headerIdx[norm]].trim();\n      // Also check partial match\n      for(var h in headerIdx){\n        if(h.indexOf(norm)>=0||norm.indexOf(h)>=0){\n          if(vals[headerIdx[h]]!==undefined)return vals[headerIdx[h]].trim();\n        }\n      }\n    }\n    return '';\n  }\n\n  var rows=[];\n  for(var j=headerLine+1;j<lines.length;j++){\n    var l2=lines[j].trim();\n    if(!l2||l2.startsWith('#'))continue;\n    var vals=csvParseLine(l2);\n    if(!vals.some(function(v){return v.trim();}))continue;\n\n    // Get trade name \u2014 try multiple column name variants\n    var name=getVal(vals,['Trade / Discipline','Trade/Discipline','Trade Discipline','Trade','Discipline','Name']);\n    if(!name)continue;\n\n    var daily=parseFloat(getVal(vals,['Daily Rate (PHP)','Daily Rate PHP','Daily Rate','Daily']))||0;\n    var monthly=parseFloat(getVal(vals,['Monthly Rate (PHP)','Monthly Rate PHP','Monthly Rate','Monthly']))||0;\n    var ot=parseFloat(getVal(vals,['OT Rate (PHP/hr)','OT Rate PHP/hr','OT Rate PHP hr','OT Rate','OT','Overtime']))||0;\n    var currency=getVal(vals,['Currency'])||'PHP';\n    var notes=getVal(vals,['Notes','Note','Remarks'])||'';\n\n    // Auto-calculate missing rates\n    if(daily>0&&!monthly)monthly=Math.round(daily*22*100)/100;\n    if(daily>0&&!ot)ot=Math.round(daily/8*1.25*100)/100;\n\n    rows.push({\n      name:name,\n      dailyRate:daily,\n      monthlyRate:monthly,\n      overtimeRate:ot,\n      currency:currency,\n      notes:notes,\n    });\n  }\n\n  if(!rows.length)errors.push('No valid data rows found after header. Check that the \"Trade / Discipline\" column has values.');\n  return{rows:rows,errors:errors};\n}\n\n// \u2500\u2500 SHOW IMPORT MODAL \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.showTradeMasterlistImport=function(){\n  document.getElementById('genericModalTitle').textContent='Import Trade / Discipline Masterlist';\n  document.getElementById('genericModalBody').innerHTML=`\n  <div style=\"margin-bottom:12px;padding:10px 12px;background:rgba(56,139,253,.08);border:1px solid rgba(56,139,253,.2);border-radius:8px;font-size:11px;color:var(--text-secondary)\">\n    <strong style=\"color:var(--accent-blue)\"><i class=\"fas fa-info-circle\" style=\"margin-right:5px\"></i>Import Instructions</strong><br>\n    \u2022 Required column: <strong>Trade / Discipline</strong> (exact name)<br>\n    \u2022 Optional: Daily Rate, Monthly Rate, OT Rate, Currency, Notes<br>\n    \u2022 Column headers accept <code>(PHP)</code>, <code>(?)</code>, <code>(PHP/hr)</code> \u2014 all recognized<br>\n    \u2022 Lines starting with <code>#</code> are skipped<br>\n    \u2022 Existing trades matched by name \u2192 <strong>updated</strong>; new trades \u2192 <strong>added</strong>\n  </div>\n  <div style=\"display:flex;gap:8px;margin-bottom:12px\">\n    <button class=\"btn btn-secondary\" style=\"flex:1\" onclick=\"window.downloadTradeMasterlistTemplate()\">\n      <i class=\"fas fa-download\" style=\"margin-right:5px\"></i>Download Template\n    </button>\n    <button class=\"btn btn-secondary\" style=\"flex:1\" onclick=\"window.exportTradeMasterlist()\">\n      <i class=\"fas fa-file-export\" style=\"margin-right:5px\"></i>Export Current\n    </button>\n  </div>\n  <div style=\"margin-bottom:10px;display:flex;gap:20px\">\n    <label style=\"display:flex;align-items:center;gap:6px;font-size:12px;cursor:pointer\">\n      <input type=\"radio\" name=\"tradeModeRadio\" value=\"merge\" checked> Merge (safe)\n    </label>\n    <label style=\"display:flex;align-items:center;gap=6px;font-size:12px;cursor:pointer\">\n      <input type=\"radio\" name=\"tradeModeRadio\" value=\"replace\"> Replace all\n    </label>\n  </div>\n  <div class=\"form-group\">\n    <label class=\"form-label\">Select CSV File *</label>\n    <input type=\"file\" id=\"tradeImportFile\" accept=\".csv,.txt\" class=\"form-input\" style=\"padding:6px\"\n      onchange=\"window.previewTradeMasterlistImport(this)\">\n  </div>\n  <div id=\"tradeImportPreview\" style=\"margin-top:10px\"></div>`;\n  document.getElementById('genericModalFooter').innerHTML=`\n    <button class=\"btn btn-secondary\" onclick=\"closeModal('genericModal')\">Cancel</button>\n    <button class=\"btn btn-primary\" id=\"tradeImportBtn\" disabled style=\"opacity:.4;cursor:not-allowed\"\n      onclick=\"window.executeTradeMasterlistImport()\">\n      <i class=\"fas fa-file-import\"></i> Import Trades\n    </button>`;\n  if(typeof openModal==='function')openModal('genericModal');\n};\n\n// \u2500\u2500 PREVIEW \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow._tradeImportRows=null;\nwindow.previewTradeMasterlistImport=function(input){\n  var file=input.files[0];if(!file)return;\n  var reader=new FileReader();\n  reader.onload=function(e){\n    var result=_parseTradeMasterlistCSV(e.target.result);\n    window._tradeImportRows=result.rows;\n    var prev=document.getElementById('tradeImportPreview');\n    if(!prev)return;\n    if(!result.rows.length){\n      prev.innerHTML='<div style=\"padding:10px;background:rgba(248,81,73,.1);border-radius:6px;color:var(--accent-red);font-size:11px\">'\n        +'<strong>No valid rows found.</strong><br>'+(result.errors.join('<br>')||'Check column headers.')+'</div>';\n      return;\n    }\n    prev.innerHTML=`<div style=\"padding:8px 12px;background:rgba(63,185,80,.08);border:1px solid rgba(63,185,80,.2);border-radius:6px;margin-bottom:8px;font-size:12px;font-weight:600;color:var(--accent-green)\">\n      <i class=\"fas fa-check-circle\" style=\"margin-right:6px\"></i>${result.rows.length} trade(s) ready to import\n    </div>\n    <div style=\"max-height:240px;overflow-y:auto;border:1px solid var(--border);border-radius:6px\">\n      <table style=\"width:100%;border-collapse:collapse;font-size:10px\">\n        <thead><tr style=\"background:var(--bg-hover)\">\n          <th style=\"padding:5px 8px;text-align:left\">Trade</th>\n          <th style=\"padding:5px 8px;text-align:right\">Daily (\u20b1)</th>\n          <th style=\"padding:5px 8px;text-align:right\">Monthly (\u20b1)</th>\n          <th style=\"padding:5px 8px;text-align:right\">OT (\u20b1/hr)</th>\n          <th style=\"padding:5px 8px;text-align:left\">Notes</th>\n        </tr></thead>\n        <tbody>${result.rows.map(function(r,i){return(\n          '<tr style=\"border-top:1px solid var(--border);background:'+(i%2?'var(--bg-hover)':'transparent')+'\">'\n          +'<td style=\"padding:4px 8px;font-weight:600\">'+r.name+'</td>'\n          +'<td style=\"padding:4px 8px;text-align:right;font-family:var(--font-mono);color:var(--accent-green)\">'+(r.dailyRate?'\u20b1'+Number(r.dailyRate).toLocaleString():'\u2014')+'</td>'\n          +'<td style=\"padding:4px 8px;text-align:right;font-family:var(--font-mono)\">'+(r.monthlyRate?'\u20b1'+Number(r.monthlyRate).toLocaleString():'\u2014')+'</td>'\n          +'<td style=\"padding:4px 8px;text-align:right;font-family:var(--font-mono)\">'+(r.overtimeRate?r.overtimeRate:'\u2014')+'</td>'\n          +'<td style=\"padding:4px 8px;color:var(--text-muted)\">'+r.notes+'</td>'\n          +'</tr>'\n        );}).join('')}</tbody>\n      </table>\n    </div>`;\n    var btn=document.getElementById('tradeImportBtn');\n    if(btn){btn.disabled=false;btn.style.opacity='1';btn.style.cursor='pointer';}\n  };\n  reader.readAsText(file);\n};\n\n// \u2500\u2500 EXECUTE IMPORT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.executeTradeMasterlistImport=function(){\n  var rows=window._tradeImportRows;\n  if(!rows||!rows.length){showToast('No data to import','error');return;}\n  var mode=(document.querySelector('input[name=\"tradeModeRadio\"]:checked')||{}).value||'merge';\n  AppState.ensureData();\n  if(!AppState.data.trades)AppState.data.trades=[];\n  AppState.data.trades=AppState.data.trades.map(toTradeObj);\n  var added=0,updated=0;\n  if(mode==='replace'){\n    AppState.data.trades=rows;added=rows.length;\n  }else{\n    rows.forEach(function(newT){\n      var idx=AppState.data.trades.findIndex(function(t){return t.name.toLowerCase()===newT.name.toLowerCase();});\n      if(idx>=0){Object.assign(AppState.data.trades[idx],newT);updated++;}\n      else{AppState.data.trades.push(newT);added++;}\n    });\n  }\n  AppState.save();\n  window._tradeImportRows=null;\n  closeModal('genericModal');\n  showToast('Imported: '+added+' added, '+updated+' updated','success',4000);\n  if(typeof window.showTradeMasterlist==='function')window.showTradeMasterlist();\n  else if(typeof renderManpower==='function')renderManpower();\n};\n\n// \u2500\u2500 FULL MASTERLIST MODAL (with inline edit) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.showTradeMasterlist=window.showTradeMasterlist||showTradeMasterlist; // use base\nwindow.updateTradeCost=function(name,field,val){\n  AppState.ensureData();\n  var t=(AppState.data.trades||[]).find(function(x){return(x.name||x)===name;});\n  if(!t)return;\n  if(field==='notes'){t.notes=val||'';}\n  else{\n    var num=parseFloat(val)||0;\n    t[field]=num;\n    if(field==='dailyRate'&&num>0){\n      if(!t.monthlyRate||t.monthlyRate===0)t.monthlyRate=Math.round(num*22*100)/100;\n      if(!t.overtimeRate||t.overtimeRate===0)t.overtimeRate=Math.round(num/8*1.25*100)/100;\n    }\n  }\n  AppState.save();\n};\n\n// \u2500\u2500 ADD / DELETE / RENAME / RESET \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.addTradeToMasterlist=window.addTradeToMasterlist; // already on window\nwindow.deleteTrade=window.deleteTrade; // already on window\nwindow.renameTrade=window.renameTrade; // already on window\nwindow.resetDefaultTrades=window.resetDefaultTrades; // already on window\n\n\n// \u2500\u2500 PATCH mpRows for object-format trades \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar _origMpRows=window.mpRows;\nif(typeof _origMpRows==='function'){\n  window.mpRows=function(manpower){\n    if(AppState.data.trades&&AppState.data.trades.some(function(t){return typeof t==='string';}))\n      AppState.data.trades=AppState.data.trades.map(toTradeObj);\n    return _origMpRows(manpower);\n  };\n}\n\n// \u2500\u2500 Inject Trade Masterlist button into Manpower header \u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar _origRenderManpower=window.renderManpower;\nif(typeof _origRenderManpower==='function'){\n  window.renderManpower=function(){\n    _origRenderManpower();\n    setTimeout(function(){\n      var el=document.getElementById('manpower');\n      if(!el)return;\n      var hdr=el.querySelector('.section-header');\n      if(!hdr||hdr.querySelector('[data-trade-btn]'))return;\n      var btns=hdr.querySelector('div:last-child');\n      if(!btns)return;\n      var btn=document.createElement('button');\n      btn.className='btn btn-secondary btn-sm';\n      btn.setAttribute('data-trade-btn','1');\n      btn.innerHTML='<i class=\"fas fa-list\" style=\"margin-right:5px\"></i>Trade Masterlist';\n      btn.onclick=window.showTradeMasterlist;\n      btns.insertBefore(btn,btns.firstChild);\n    },60);\n  };\n}\n\nconsole.log('[SHIC Patch v1.0.1] Trade Cost Masterlist loaded \u2014 '+((AppState.data&&AppState.data.trades)||[]).length+' trades');\nshowToast('Trade Masterlist ready \u2014 import your CSV now','success',3000);\n\n})();\n",
  "delete_allocations": "// PATCH_ID: shic-patch-delete-all-allocations-v1.0.0\n// PATCH_VERSION: 1.0.0\n// PATCH_TYPE: persistent\n// DESCRIPTION: Adds \"Delete All Allocations\" button (Admin only) to each project's Resource Allocation tab. Can delete all allocations, or filter by resource type. Also adds delete all usage logs option. Confirmation required.\n\n(function(){\n'use strict';\n\n// \u2500\u2500 Admin check (handles both window and closure-scope variables) \u2500\u2500\nfunction isAdmin(){\n  // Try closure-scope variables first (app stores them as let/const, not on window)\n  try{\n    // eval gives access to the script's closure scope\n    var profile=eval('typeof _currentUserProfile!==\"undefined\"?_currentUserProfile:null');\n    if(profile&&profile.isAdmin)return true;\n    var user=eval('typeof _currentUser!==\"undefined\"?_currentUser:null');\n    if(user&&typeof isAdminEmail==='function'&&isAdminEmail(user.email||''))return true;\n  }catch(e){}\n  // Fallback: check window properties\n  if(window._currentUserProfile&&window._currentUserProfile.isAdmin)return true;\n  if(window._currentUser&&typeof isAdminEmail==='function'&&isAdminEmail(window._currentUser.email||''))return true;\n  // Fallback: check DOM (sidebar shows \"Admin\" label)\n  var sidebar=document.querySelector('.user-name,.sidebar-user,.user-role');\n  if(sidebar&&/admin/i.test(sidebar.textContent))return true;\n  // Fallback: check user management toggle state\n  var adminBadge=document.querySelector('.badge-admin,[data-admin=\"true\"]');\n  if(adminBadge)return true;\n  return false;\n}\n\n// \u2500\u2500 Delete all allocations for a project (with optional type filter) \u2500\u2500\nwindow.deleteAllAllocations = function(pid, resourceType){\n  if(!isAdmin()){\n    showToast('Admin access required','error');\n    return;\n  }\n  pid = pid || window.detailProjectId;\n  if(!pid){ showToast('No project selected','error'); return; }\n\n  AppState.ensureData();\n  var allocs = (AppState.data.resourceAllocations||[]).filter(function(a){ return a.projectId===pid; });\n  var logs   = (AppState.data.resourceUsageLogs||[]).filter(function(l){ return l.projectId===pid; });\n\n  if(resourceType && resourceType !== 'all'){\n    allocs = allocs.filter(function(a){ return a.resourceType===resourceType; });\n    logs   = logs.filter(function(l){ return l.resourceType===resourceType; });\n  }\n\n  if(!allocs.length){\n    showToast('No allocations to delete'+(resourceType&&resourceType!=='all'?' for '+resourceType:''),'warning');\n    return;\n  }\n\n  var label = resourceType && resourceType!=='all' ? resourceType+' allocations' : 'ALL allocations';\n  var msg = 'DELETE '+label+' for project '+pid+'?\\n\\n'\n    +'\u2022 '+allocs.length+' allocation record(s) will be removed\\n'\n    +'\u2022 '+logs.length+' usage log(s) will also be removed\\n\\n'\n    +'This CANNOT be undone. Export a backup first if needed.';\n\n  if(!confirm(msg)) return;\n  if(!confirm('FINAL CONFIRMATION: Permanently delete '+allocs.length+' allocation(s)?')) return;\n\n  // Get IDs to remove\n  var allocIds = new Set(allocs.map(function(a){ return a.id; }));\n\n  // Remove from data\n  AppState.data.resourceAllocations = (AppState.data.resourceAllocations||[]).filter(function(a){\n    return !(a.projectId===pid && allocIds.has(a.id));\n  });\n  AppState.data.resourceUsageLogs = (AppState.data.resourceUsageLogs||[]).filter(function(l){\n    return !(l.projectId===pid && allocIds.has(l.allocationId));\n  });\n\n  AppState.save();\n\n  closeModal('genericModal');\n  if(typeof renderDetailAllocation==='function') renderDetailAllocation();\n  showToast('Deleted '+allocs.length+' allocation(s) from '+pid,'warning',4000);\n};\n\n// \u2500\u2500 Show the Delete All modal \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.showDeleteAllAllocationsModal = function(pid){\n  if(!isAdmin()){\n    showToast('Admin access required to delete allocations','error');\n    return;\n  }\n  pid = pid || window.detailProjectId;\n  if(!pid){ showToast('No project selected','error'); return; }\n\n  AppState.ensureData();\n  var allocs = (AppState.data.resourceAllocations||[]).filter(function(a){ return a.projectId===pid; });\n  var logs   = (AppState.data.resourceUsageLogs||[]).filter(function(l){ return l.projectId===pid; });\n\n  if(!allocs.length){\n    showToast('No allocations found for project '+pid,'warning');\n    return;\n  }\n\n  // Count by type\n  var types = ['Personnel','Equipment','Tool','Vehicle','Consumable','Material','Manpower'];\n  var typeColors = {\n    Personnel:'#388bfd',Equipment:'#f0a450',Tool:'#bc8cff',Vehicle:'#39d3f2',\n    Consumable:'#3fb950',Material:'#fb8f44',Manpower:'#f85149'\n  };\n  var typeCounts = {};\n  types.forEach(function(t){\n    typeCounts[t] = allocs.filter(function(a){ return a.resourceType===t; }).length;\n  });\n\n  var totalLogs = logs.length;\n\n  document.getElementById('genericModalTitle').textContent = 'Delete Allocations \u2014 '+pid;\n  document.getElementById('genericModalBody').innerHTML =\n    '<div style=\"padding:12px 14px;background:rgba(248,81,73,.08);border:1px solid rgba(248,81,73,.2);border-radius:8px;margin-bottom:14px\">'\n    +'<div style=\"font-size:12px;font-weight:700;color:var(--accent-red);margin-bottom:5px\">'\n    +'<i class=\"fas fa-exclamation-triangle\" style=\"margin-right:6px\"></i>Admin Action \u2014 Permanent Deletion'\n    +'</div>'\n    +'<div style=\"font-size:11px;color:var(--text-secondary)\">'\n    +'This will permanently remove allocations and their usage logs from project <strong>'+pid+'</strong>. '\n    +'<strong>This cannot be undone.</strong> Export a backup first if needed.'\n    +'</div>'\n    +'</div>'\n\n    // Summary\n    +'<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px\">'\n    +'<div style=\"padding:10px 14px;background:var(--bg-hover);border-radius:8px;border-left:3px solid var(--accent-red)\">'\n    +'<div style=\"font-size:22px;font-weight:800;color:var(--accent-red)\">'+allocs.length+'</div>'\n    +'<div style=\"font-size:11px;color:var(--text-secondary)\">Total Allocations</div>'\n    +'</div>'\n    +'<div style=\"padding:10px 14px;background:var(--bg-hover);border-radius:8px;border-left:3px solid var(--accent-amber)\">'\n    +'<div style=\"font-size:22px;font-weight:800;color:var(--accent-amber)\">'+totalLogs+'</div>'\n    +'<div style=\"font-size:11px;color:var(--text-secondary)\">Usage Logs (also deleted)</div>'\n    +'</div>'\n    +'</div>'\n\n    // By type\n    +'<div style=\"font-size:12px;font-weight:600;margin-bottom:8px\">Delete by Resource Type:</div>'\n    +'<div style=\"display:flex;flex-direction:column;gap:6px\">'\n    + types.filter(function(t){ return typeCounts[t]>0; }).map(function(t){\n        var c = typeColors[t]||'#8b949e';\n        var cnt = typeCounts[t];\n        return '<div style=\"display:flex;align-items:center;gap:10px;padding:8px 12px;background:var(--bg-hover);border-radius:6px;border:1px solid var(--border)\">'\n          +'<div style=\"width:8px;height:8px;border-radius:50%;background:'+c+';flex-shrink:0\"></div>'\n          +'<div style=\"flex:1;font-size:12px;font-weight:500\">'+t+'</div>'\n          +'<span style=\"font-size:11px;font-weight:700;background:'+c+'22;color:'+c+';padding:1px 8px;border-radius:10px\">'+cnt+' records</span>'\n          +'<button class=\"btn btn-danger btn-sm\" style=\"min-width:80px\" '\n          +'onclick=\"window.deleteAllAllocations(\\''+pid+'\\',\\''+t+'\\')\">'\n          +'<i class=\"fas fa-trash\" style=\"margin-right:4px\"></i>Delete</button>'\n          +'</div>';\n      }).join('')\n    +'</div>'\n\n    // Delete all button\n    +'<div style=\"margin-top:14px;padding-top:14px;border-top:1px solid var(--border)\">'\n    +'<button class=\"btn btn-danger\" style=\"width:100%;font-size:13px;padding:10px\" '\n    +'onclick=\"window.deleteAllAllocations(\\''+pid+'\\',\\'all\\')\">'\n    +'<i class=\"fas fa-trash-alt\" style=\"margin-right:8px\"></i>'\n    +'Delete ALL '+allocs.length+' Allocations + '+totalLogs+' Logs'\n    +'</button>'\n    +'</div>';\n\n  document.getElementById('genericModalFooter').innerHTML =\n    '<button class=\"btn btn-secondary\" onclick=\"closeModal(\\'genericModal\\')\">Cancel</button>';\n\n  if(typeof openModal==='function') openModal('genericModal');\n};\n\n// \u2500\u2500 Inject button into renderDetailAllocation \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar _origRDA = window.renderDetailAllocation;\nwindow.renderDetailAllocation = function(){\n  if(typeof _origRDA==='function') _origRDA();\n\n  // Only inject for admins\n  if(!isAdmin()) return;\n\n  setTimeout(function(){\n    var pid = window.detailProjectId;\n    if(!pid) return;\n\n    // Find the allocation tab content\n    var tabContent = document.getElementById('detailTabContent');\n    if(!tabContent) return;\n\n    // Check if button already injected\n    if(tabContent.querySelector('[data-delete-alloc-btn]')) return;\n\n    // Find the allocation table card header area\n    var sectionHeader = tabContent.querySelector('.section-header');\n    var btnArea = sectionHeader ? sectionHeader.querySelector('div:last-child') : null;\n\n    if(!btnArea){\n      // Fallback: find any button group in the tab\n      var btns = tabContent.querySelector('.card .section-header');\n      btnArea = btns ? btns.lastElementChild : null;\n    }\n\n    if(btnArea){\n      var delBtn = document.createElement('button');\n      delBtn.className = 'btn btn-danger btn-sm';\n      delBtn.setAttribute('data-delete-alloc-btn','1');\n      delBtn.innerHTML = '<i class=\"fas fa-trash-alt\" style=\"margin-right:5px\"></i>Delete All';\n      delBtn.title = 'Delete all allocations for this project (Admin only)';\n      delBtn.onclick = function(){ window.showDeleteAllAllocationsModal(pid); };\n      btnArea.insertBefore(delBtn, btnArea.firstChild);\n    } else {\n      // Inject a floating action bar at the top\n      var actionBar = document.createElement('div');\n      actionBar.setAttribute('data-delete-alloc-btn','1');\n      actionBar.style.cssText = 'display:flex;justify-content:flex-end;margin-bottom:10px';\n      actionBar.innerHTML =\n        '<button class=\"btn btn-danger btn-sm\" onclick=\"window.showDeleteAllAllocationsModal(\\''+pid+'\\')\">'+\n        '<i class=\"fas fa-trash-alt\" style=\"margin-right:5px\"></i>Delete All Allocations (Admin)'+\n        '</button>';\n      tabContent.insertBefore(actionBar, tabContent.firstChild);\n    }\n  }, 120);\n};\n\n// Re-render if currently on allocation tab\nif(typeof window.detailProjectId !== 'undefined' && window.detailProjectId &&\n   typeof renderDetailAllocation === 'function' && isAdmin()){\n  setTimeout(renderDetailAllocation, 300);\n}\n\nconsole.log('[SHIC Patch] Delete All Allocations loaded \u2014 Admin:', isAdmin(), '| profile:', typeof _currentUserProfile!=='undefined'?_currentUserProfile?.name:'(not in scope)');\n// Show status regardless\ntry{\n  var _p=eval('typeof _currentUserProfile!==\"undefined\"?_currentUserProfile:null');\n  console.log('[SHIC] Current user profile:', _p?.name, '| isAdmin:', _p?.isAdmin);\n}catch(e){}\nshowToast('Delete All Allocations patch loaded','info',2000);\n\n})();\n",
  "login_button_wire": "// PATCH_ID: shic-patch-fix-login-and-clear-v1.0.0\n// PATCH_VERSION: 1.0.1\n// PATCH_TYPE: persistent\n// DESCRIPTION: Fixes Sign In button doing nothing. Directly wires all auth button handlers to real functions. Removes shim interference.\n\n(function(){\n'use strict';\n\n// \u2500\u2500 DIRECTLY WIRE ALL AUTH BUTTONS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Bypass any shim/stub issues by directly patching the DOM elements\nfunction wireAuthButtons(){\n  // Sign in button\n  var loginBtn = document.getElementById('loginBtn');\n  if(loginBtn){\n    loginBtn.onclick = null;\n    loginBtn.addEventListener('click', function(e){\n      e.preventDefault();\n      if(typeof doM365Login === 'function') doM365Login();\n      else if(typeof doLogin === 'function') doLogin();\n      else if(typeof window._shic_doLogin === 'function') window._shic_doLogin();\n      else console.error('[SHIC] doLogin not found');\n    });\n    console.log('[Auth Fix] Login button wired');\n  }\n\n  // Password enter key\n  var passInput = document.getElementById('loginPass');\n  if(passInput){\n    passInput.onkeydown = null;\n    passInput.addEventListener('keydown', function(e){\n      if(e.key === 'Enter'){\n        if(typeof doM365Login === 'function') doM365Login();\n        else if(typeof doLogin === 'function') doLogin();\n        else if(typeof window._shic_doLogin === 'function') window._shic_doLogin();\n      }\n    });\n  }\n\n  // Register button\n  var regBtn = document.getElementById('registerBtn') || document.querySelector('[onclick*=\"doRegister\"]');\n  if(regBtn){\n    regBtn.onclick = null;\n    regBtn.addEventListener('click', function(){\n      if(typeof doRegister === 'function') doRegister();\n    });\n  }\n\n  // Password toggle buttons\n  document.querySelectorAll('[onclick*=\"togglePassView\"]').forEach(function(el){\n    var match = el.getAttribute('onclick').match(/togglePassView\\('([^']+)','([^']+)'\\)/);\n    if(match){\n      el.onclick = null;\n      (function(inputId, iconId){\n        el.addEventListener('click', function(){\n          if(typeof togglePassView === 'function') togglePassView(inputId, iconId);\n        });\n      })(match[1], match[2]);\n    }\n  });\n\n  // Connect button on setup screen\n  var connectBtn = document.querySelector('[onclick*=\"connectFromLoginPage\"]');\n  if(connectBtn){\n    connectBtn.onclick = null;\n    connectBtn.addEventListener('click', function(){\n      if(typeof connectFromLoginPage === 'function') connectFromLoginPage();\n    });\n  }\n}\n\n// \u2500\u2500 RUN NOW AND ON EVERY FORM SWITCH \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Wire immediately\nwireAuthButtons();\n\n// Also wire after showAuthForm switches forms\nvar _origShowAuthForm = window.showAuthForm;\nwindow.showAuthForm = function(form){\n  if(typeof _origShowAuthForm === 'function') _origShowAuthForm(form);\n  else if(typeof showAuthForm === 'function' && showAuthForm !== window.showAuthForm) showAuthForm(form);\n  setTimeout(wireAuthButtons, 50);\n};\n\n// Also wire when auth overlay is shown\nvar _origShowAuthOverlay = window.showAuthOverlay;\nwindow.showAuthOverlay = function(show){\n  if(typeof _origShowAuthOverlay === 'function') _origShowAuthOverlay(show);\n  if(show) setTimeout(wireAuthButtons, 100);\n};\n\n// \u2500\u2500 ENSURE window.doLogin POINTS TO REAL FUNCTION \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Override the shim with the actual function reference\nsetTimeout(function(){\n  if(typeof doLogin === 'function'){\n    window.doLogin = doLogin;\n    window.doRegister = doRegister;\n    window.doForgotPassword = doForgotPassword;\n    window.togglePassView = togglePassView;\n    window.showAuthForm = showAuthForm;\n    window.connectFromLoginPage = connectFromLoginPage;\n    window.doLogout = doLogout;\n    wireAuthButtons(); // re-wire after ensuring functions are set\n    console.log('[Auth Fix] All auth functions directly assigned to window');\n  }\n}, 500);\n\n// \u2500\u2500 ALSO FIX clearAllData \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.clearAllData = function(){\n  if(!confirm('\u26a0 CLEAR ALL DATA?\\n\\nThis will permanently delete everything.\\nExport a backup first!'))return;\n  if(!confirm('Are you absolutely sure? This CANNOT be undone.'))return;\n  try{if(window._auth)window._auth.signOut();}catch(e){}\n  ['pm_data','pm_theme','shic_data_version','shic_applied_patches',\n   'shic_persistent_patches','shic_offline_queue','shic_offline_data',\n  ].forEach(function(k){try{localStorage.removeItem(k);}catch(e){}});\n  showToast('All data cleared \u2014 reloading...','warning',1500);\n  setTimeout(function(){location.reload();},1500);\n};\n\nconsole.log('[SHIC Patch v1.0.1] Auth button fix loaded');\n\n})();\n",
  "currency_fix": "// PATCH_ID: shic-patch-currency-fix-v1.0.0\n// PATCH_VERSION: 1.0.0\n// PATCH_TYPE: persistent\n// DESCRIPTION: Fixes all hardcoded USD/\u20b1 labels to use the currency set in Company Settings. Budget field in New Project now shows correct currency. All form labels and table headers update dynamically.\n\n(function(){\n'use strict';\n\n// \u2500\u2500 Helper: get current currency symbol \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction getCurrency(){\n  try{\n    var s=AppState&&AppState.data&&AppState.data.settings;\n    var code=s&&s.currency?s.currency:'PHP';\n    var symbols={'PHP':'\u20b1','USD':'$','EUR':'\u20ac','SAR':'\ufdfc','GBP':'\u00a3','SGD':'S$','AUD':'A$','JPY':'\u00a5','CNY':'\u00a5','HKD':'HK$'};\n    return{code:code,symbol:symbols[code]||code+' '};\n  }catch(e){return{code:'PHP',symbol:'\u20b1'};}\n}\n\n// \u2500\u2500 1. Fix modal labels after they render \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction fixModalCurrencyLabels(){\n  var cur=getCurrency();\n  var sym=cur.symbol;\n  var code=cur.code;\n\n  // Fix all visible form labels containing \"USD\" or wrong currency\n  document.querySelectorAll('label.form-label, th, .form-label').forEach(function(el){\n    var text=el.textContent||el.innerText||'';\n    if(text.includes('(USD)')){\n      el.innerHTML=el.innerHTML.replace(/\\(USD\\)/g,'('+code+')');\n    }\n  });\n\n  // Fix Budget (USD) specifically in project form\n  var budgetLabel=document.getElementById('pBudget');\n  if(budgetLabel&&budgetLabel.previousElementSibling){\n    var lbl=budgetLabel.previousElementSibling;\n    if(lbl&&lbl.textContent.includes('USD')){\n      lbl.textContent=lbl.textContent.replace('USD',code);\n    }\n  }\n  // Find by text content\n  document.querySelectorAll('label').forEach(function(lbl){\n    if(lbl.htmlFor==='pBudget'||lbl.textContent.includes('Budget (USD)')){\n      lbl.textContent=lbl.textContent.replace('(USD)','('+code+')');\n    }\n  });\n}\n\n// \u2500\u2500 2. Patch showTaskForm/showProjectForm to use dynamic currency \u2500\u2500\nvar _origShowProjectForm=window.showProjectForm||window.showAddProject;\n\n// Intercept genericModal opens to fix currency labels\nvar _origOpenModal=window.openModal;\nwindow.openModal=function(id){\n  if(typeof _origOpenModal==='function')_origOpenModal(id);\n  // Fix currency labels after modal renders\n  setTimeout(fixModalCurrencyLabels,30);\n};\n\n// \u2500\u2500 3. Patch renderPage to fix labels after each page render \u2500\u2500\nvar _origRenderPage=window.renderPage;\nwindow.renderPage=function(page){\n  if(typeof _origRenderPage==='function')_origRenderPage(page);\n  setTimeout(fixPageCurrencyLabels,100);\n};\n\nfunction fixPageCurrencyLabels(){\n  var cur=getCurrency();\n  var sym=cur.symbol;\n  var code=cur.code;\n\n  // Fix all table headers with (\u20b1) or (USD) when currency isn't PHP\n  if(code!=='PHP'){\n    document.querySelectorAll('th,td,.form-label,label').forEach(function(el){\n      var html=el.innerHTML||'';\n      if(html.includes('(\u20b1)')||html.includes('\u20b1')){\n        // Only fix text nodes, not attribute values\n        if(el.children.length===0){\n          el.textContent=el.textContent.replace(/\u20b1/g,sym);\n        }\n      }\n      if(html.includes('(USD)')){\n        el.innerHTML=html.replace(/\\(USD\\)/g,'('+code+')');\n      }\n    });\n  }else if(code==='PHP'){\n    // Make sure \u20b1 is used everywhere (default)\n    document.querySelectorAll('th,td,.form-label,label').forEach(function(el){\n      if(el.children.length===0&&(el.textContent||'').includes('(USD)')){\n        el.textContent=el.textContent.replace(/\\(USD\\)/g,'(\u20b1)');\n      }\n    });\n  }\n}\n\n// \u2500\u2500 4. Patch the project form template to use dynamic currency \u2500\u2500\nvar _origShowTaskForm=window.showTaskForm;\n// The core fix: patch the HTML template that creates the Budget label\n// We intercept the innerHTML setter on genericModalBody\nvar modalBody=document.getElementById('genericModalBody');\nif(modalBody){\n  var _origInnerHTML=Object.getOwnPropertyDescriptor(Element.prototype,'innerHTML');\n  // Don't override innerHTML globally \u2014 too risky\n  // Instead just run fixModalCurrencyLabels after a short delay on every modal open\n}\n\n// \u2500\u2500 5. Direct DOM fix for the project form \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Patch showProjectForm (called when + New Project is clicked)\nfunction patchProjectForm(){\n  var originalFn=window.showProjectForm||window.showNewProjectForm;\n  var fnName=window.showProjectForm?'showProjectForm':'showNewProjectForm';\n\n  // Find the function by looking at what creates #pBudget\n  // Search all window functions\n  ['showProjectForm','showNewProjectForm','showAddProject','addProject'].forEach(function(name){\n    if(typeof window[name]==='function'){\n      var orig=window[name];\n      window[name]=function(){\n        orig.apply(this,arguments);\n        setTimeout(function(){\n          var cur=getCurrency();\n          // Find the Budget label\n          var labels=document.querySelectorAll('label');\n          labels.forEach(function(lbl){\n            var t=lbl.textContent||'';\n            if(t.includes('Budget')){\n              lbl.textContent=t.replace(/\\(USD\\)/g,'('+cur.code+')')\n                               .replace(/Budget \\(\u20b1\\)/g,'Budget ('+cur.code+')')\n                               .replace(/Budget$/,'Budget ('+cur.code+')');\n            }\n          });\n        },50);\n      };\n      console.log('[Currency Patch] Patched '+name);\n    }\n  });\n}\npatchProjectForm();\n\n// \u2500\u2500 6. Patch fmtNum to use correct currency symbol \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar _origFmtNum=window.fmtNum;\nif(typeof fmtNum==='function'){\n  window.fmtNum=function(n,withSymbol){\n    var formatted=typeof _origFmtNum==='function'?_origFmtNum(n):Number(n||0).toLocaleString('en-PH',{minimumFractionDigits:0,maximumFractionDigits:2});\n    return formatted;\n  };\n}\n\n// \u2500\u2500 7. Run immediately to fix any currently visible labels \u2500\u2500\u2500\u2500\nsetTimeout(fixModalCurrencyLabels,200);\nsetTimeout(fixPageCurrencyLabels,300);\n\n// Also fix on settings save\nvar _origSaveSettings=window.saveSettings;\nwindow.saveSettings=function(){\n  if(typeof _origSaveSettings==='function')_origSaveSettings();\n  setTimeout(function(){\n    fixPageCurrencyLabels();\n    console.log('[Currency Patch] Currency updated to',getCurrency().code);\n    showToast('Currency updated to '+getCurrency().code+' ('+getCurrency().symbol+')','success',2000);\n  },200);\n};\n\n// \u2500\u2500 8. Watch for modal opens via MutationObserver \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ntry{\n  var observer=new MutationObserver(function(mutations){\n    mutations.forEach(function(m){\n      if(m.type==='attributes'&&m.attributeName==='style'){\n        var el=m.target;\n        if(el.id==='genericModal'&&el.style.display!=='none'){\n          setTimeout(fixModalCurrencyLabels,30);\n        }\n      }\n      if(m.type==='childList'&&m.target.id==='genericModalBody'){\n        setTimeout(fixModalCurrencyLabels,30);\n      }\n    });\n  });\n  var modal=document.getElementById('genericModal');\n  var modalBodyEl=document.getElementById('genericModalBody');\n  if(modal)observer.observe(modal,{attributes:true,attributeFilter:['style']});\n  if(modalBodyEl)observer.observe(modalBodyEl,{childList:true,subtree:false});\n  console.log('[Currency Patch] MutationObserver watching modal');\n}catch(e){\n  console.warn('[Currency Patch] MutationObserver not available:',e.message);\n}\n\nconsole.log('[SHIC Patch] Currency Fix loaded \u2014 current currency:',getCurrency().code,getCurrency().symbol);\n\n})();\n"
};

function runBuiltinPatches(){
  // Temporarily suppress showToast during builtin init (fires before UI is ready)
  const _origToast = window.showToast;
  window.showToast = function(){};  // suppress init-time toasts
  Object.entries(BUILTIN_PATCHES).forEach(([key,code])=>{
    try{
      eval(code);
    }catch(e){
      console.error('[SHIC] Builtin patch error ('+key+'):',e.message);
    }
  });
  window.showToast = _origToast;  // restore
  console.log('[SHIC] '+Object.keys(BUILTIN_PATCHES).length+' builtin feature modules loaded');
}


function init(){
runBuiltinPatches(); // Apply builtin features (task import, trade costs, etc.)
// ALWAYS load local data first — never wipe pm_data on startup.
// SharePoint / localStorage is the safety net; sync happens after login only.
AppState.load();
_restoreLocalData(); // also tries shic_data_backup if pm_data is empty
migrateData();
runVersionedMigrations();
initOneDriveSync();
// Boot is handled by DOMContentLoaded above
initOfflineSupport();
// Re-run persistent patches LAST so overrides apply after all functions are defined
setTimeout(runPersistentPatches,200);
document.documentElement.setAttribute('data-theme',AppState.theme);
// Apply theme to toggle icon if it exists (safe before auth)
const _themeIcon=$('#themeIcon');if(_themeIcon)_themeIcon.className=AppState.theme==='dark'?'fas fa-moon':'fas fa-sun';
// App UI (sidebar, dashboard) is rendered AFTER login in doM365Login() — not here.
// This prevents the app from being accessible without M365 authentication.
setInterval(()=>{if(_m365LoggedIn)AppState.save();},30000);

  // ── Register all functions on window for onclick handlers ─
  [showAuthForm,togglePassView,doLogout,
   selfApproveAsAdmin,
   syncOfflineQueue,
   syncToOneDrive,syncFromOneDrive,connectOneDrive,disconnectOneDrive,
   odAutoSyncToggle,odSaveClientId,
   saveSettings,exportAllData,importData,clearAllData,
   showPatchImport,applyPatch,removePatch,previewPatchFile,checkForUpdates,
   renderUserManagement,approveUser,rejectUser,suspendUser,toggleAdmin,
   deleteUser,restoreUser,showModuleAccess,saveModuleAccess,
   hasModulePermission,getModulePermission,getModulePerms,setModulePerms,PERM_LEVELS,PERM_LABELS,PERM_COLORS,
   uploadDoc,showDocDetail,saveDocDetail,downloadDoc,viewDoc,deleteDoc,
   attachFileToDoc,renderDocTable,searchDocs,exportDocsCsv,
   showAddProcurement,showEditProcurement,saveProcurement,deleteProcurement,importProcurement,previewProcImport,executeProcImport,
   showProcDetail,changeProcStage,showProcLogUpdate,showProcLogUpdateGlobal,
   saveProcLogUpdate,saveProcLogUpdateGlobal,deleteProcLog,exportProcurementCSV,
   procFormStatusChange,procAttachFile,procDownloadAttachment,
   procViewAttachment,procRemoveAttachment,renderProcTab,
   showProjectDetail,renderDetailTab,saveDetailOverview,
   deleteDetailTask,
   showAllocateResource,showLogUsage,
   importAllocExcel,exportAllocExcel,importUsageLogExcel,exportUsageLogExcel,
   previewAllocImport,executeAllocImport,previewLogImport,executeLogImport,cleanGhostAllocations,
   downloadTemplate,importManpower,previewMpImport,executeMpImport,showMlImport,
   showAddPO,showAddTeamMember,saveTeamMember,removeTeamMember,
   showAddCost,saveCostItem,showAddQAQC,saveQAQCItem,
   ganttQuickRange,renderGantt,
   toggleTheme,buildSidebar,navigate,
  ].forEach(fn=>{try{if(fn&&fn.name)window[fn.name]=fn;}catch(e){}});
}